  }, [selected])
  return (
    // <div className="min-h-screen bg-grid">
    <BrowserRouter>
      <Routes>
        <Route element={<Layout/>}>
          <Route path="/" element={<Home/>} />
          <Route path="/select" element={<SelectStack />} />
          <Route path="/questions/:selected" element={<Questions/>} />
          <Route path="/results" element={<Results/>} />
        </Route>
      </Routes>
    </BrowserRouter>
  );
}

export default App;
